#include "mcp9808.h"
#include <Wire.h>
#include <Adafruit_MCP9808.h>
static Adafruit_MCP9808 t;
static float _t=0;static unsigned long _l=0;
void mcp9808_setup(){Wire.begin();if(!t.begin(0x18)){Serial.println("[mcp9808] Fail!");return;}t.setResolution(3);Serial.println("[mcp9808] OK");}
void mcp9808_loop(){if(millis()-_l<1000)return;_l=millis();_t=t.readTempC();}
float mcp9808_get_temp(){return _t;}
